INSERT INTO flows (id, lesson_id, title, status, reward_xp, slides)
VALUES ('f2710000-0000-4000-8000-000000000002', 'a2710000-0000-4000-8000-000000000002', 'Bài 2: Cụm Mi – Fa – Sol', 'published', 10, '[{"id":"c1","order":1,"logic":"DAN","type":"callout","title":"Cụm Mi – Fa – Sol","interactive":{"variant":"teacher"},"content":"Bạn đã chơi được nốt <b>Mi</b>. Hôm nay thêm <b>2 nốt mới</b> ngay cạnh nó — <b>Fa</b> và <b>Sol</b> — để có <b>cụm nốt đầu tiên</b>. Cùng một dây vẫn tạo ra nhiều nốt khác nhau."},{"id":"c2","order":2,"logic":"NHAN","type":"note_show","title":"Mi — ôn lại","interactive":{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"showStaff":true,"showFretboard":true,"caption":"<b>Mi</b> bạn đã biết — dây 1 <b>buông</b> (○). Nghe lại cho chắc tai."}},{"id":"c3","order":3,"logic":"NHAN","type":"note_show","title":"Fa — nốt mới","interactive":{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8,"showStaff":true,"showFretboard":true,"caption":"<b>Fa</b> — nốt mới: cùng dây, bấm <b>ngăn 1</b>. Trên khuông, Fa nằm ngay <b>trên</b> Mi một bậc."}},{"id":"c4","order":4,"logic":"NHAN","type":"note_show","title":"Sol — nốt mới","interactive":{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9,"showStaff":true,"showFretboard":true,"caption":"<b>Sol</b> — nốt mới: cùng dây, bấm <b>ngăn 3</b>. Cao hơn Fa một bậc nữa."}},{"id":"c5","order":5,"logic":"LAM","type":"note_practice","title":"Đánh theo: Mi – Fa – Sol","interactive":{"notes":[{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8},{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8},{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9}],"hint":"Nếu bạn đã biết nhạc lý: giai đoạn này ta chưa học trường độ, nên mọi nốt đều vẽ giống nhau — dù khi phát, có nốt ngân dài, có nốt ngắn. Đây là chủ ý; nốt đen, trắng, tròn sẽ học ở phần sau."}},{"id":"c6","order":6,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình gảy được 3 nốt Mi – Fa – Sol, tiếng rõ","Mình thấy 3 nốt đi LÊN dần trên khuông nhạc","Cùng một dây mà ra được 3 nốt khác nhau"]}},{"id":"c7","order":7,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Giỏi lắm! Bạn đã có <b>cụm nốt đầu tiên</b>. Bài sau, ta ghép 3 nốt này thành một <b>câu nhạc</b> — để thấy nốt là để tạo giai điệu, không phải học thuộc."}]'::jsonb)
ON CONFLICT (id) DO UPDATE SET lesson_id = EXCLUDED.lesson_id, title = EXCLUDED.title, status = EXCLUDED.status, reward_xp = EXCLUDED.reward_xp, slides = EXCLUDED.slides;

