INSERT INTO flows (id, lesson_id, title, status, reward_xp, slides)
VALUES ('f2710000-0000-4000-8000-000000000003', 'a2710000-0000-4000-8000-000000000003', 'Bài 3: Câu nhạc đầu tiên', 'published', 10, '[{"id":"n1","order":1,"logic":"DAN","type":"callout","title":"Câu nhạc đầu tiên","interactive":{"variant":"teacher"},"content":"Ba nốt <b>Mi – Fa – Sol</b> không chỉ để học thuộc. Ghép lại, ta có một <b>câu nhạc</b>: <b>Mi – Fa – Sol – Fa – Mi</b> — đi lên rồi đi xuống."},{"id":"n2","order":2,"logic":"NGHI","type":"text","title":"Một giai điệu nhỏ","content":"<p style=\"font-size:16px;line-height:1.7;margin:0;color:#3A352F\">Đọc theo thứ tự: <b>Mi → Fa → Sol → Fa → Mi</b>.<br/>Đi <b>lên</b> 3 nốt rồi đi <b>xuống</b> lại. Đó đã là một giai điệu — nốt nhạc dùng để vậy đó.</p>"},{"id":"n3","order":3,"logic":"LAM","type":"note_practice","title":"Đánh theo câu nhạc","interactive":{"notes":[{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8},{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7}]}},{"id":"n4","order":4,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình chơi liền được câu Mi – Fa – Sol – Fa – Mi","Mình nghe ra giai điệu đi lên rồi đi xuống"]}},{"id":"n5","order":5,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Tuyệt! Bạn vừa chơi <b>câu nhạc đầu tiên</b>. Nốt nhạc là để <b>tạo giai điệu</b>, không phải học thuộc rời rạc. Bài sau ta thêm một cụm nốt mới."}]'::jsonb)
ON CONFLICT (id) DO UPDATE SET lesson_id = EXCLUDED.lesson_id, title = EXCLUDED.title, status = EXCLUDED.status, reward_xp = EXCLUDED.reward_xp, slides = EXCLUDED.slides;

