VALUES ('f2710000-0000-4000-8000-000000000006', 'a2710000-0000-4000-8000-000000000006', 'Bài 6: Đọc câu nhạc qua 2 dây', 'published', 10, '[{"id":"t1","order":1,"logic":"DAN","type":"callout","title":"Câu nhạc qua 2 dây","interactive":{"variant":"teacher"},"content":"Bài hát thật luôn <b>nhảy qua lại</b> giữa các dây. Thử câu <b>Mi – Rê – Đô – Rê – Mi</b> — đi xuống dây cạnh rồi quay về."},{"id":"t2","order":2,"logic":"NGHI","type":"text","title":"Chuyển dây","content":"<p style=\"font-size:16px;line-height:1.7;margin:0;color:#3A352F\"><b>Mi</b> nằm một dây; <b>Rê</b> và <b>Đô</b> nằm dây cạnh.<br/>Đọc nốt là <b>chuyển dây</b> mượt theo giai điệu — đây mới là năng lực thật của tỉa nốt.</p>"},{"id":"t3","order":3,"logic":"LAM","type":"note_practice","title":"Đánh theo: Mi – Rê – Đô – Rê – Mi","interactive":{"notes":[{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7}]}},{"id":"t4","order":4,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình chuyển được giữa 2 dây mà tiếng vẫn đều","Mình chơi liền câu Mi – Rê – Đô – Rê – Mi"]}},{"id":"t5","order":5,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Xuất sắc! Bạn đã đọc và chơi được một câu nhạc <b>qua 2 dây</b>. Đây là nền của mọi bài tỉa nốt về sau — nốt nối thành giai điệu, dây chỉ là nơi đặt ngón."}]'::jsonb)
