INSERT INTO flows (id, lesson_id, title, status, reward_xp, slides)
VALUES ('f2720000-0000-4000-8000-000000000003', 'a2720000-0000-4000-8000-000000000003', 'Bài 3: Vùng nốt mở rộng', 'published', 10, '[{"id":"v1","order":1,"logic":"DAN","type":"callout","title":"Vùng nốt mở rộng","interactive":{"variant":"teacher"},"content":"Gộp lại: <b>Rê – Mi – Fa – Sol – La</b> — một vùng nốt <b>thấp hơn</b>, nối ngay dưới vùng đã học."},{"id":"v2","order":2,"logic":"NGHI","type":"text","title":"5 nốt đi lên","content":"<p style=\"font-size:16px;line-height:1.7;margin:0;color:#3A352F\">Năm nốt đi <b>lên dần</b>: Rê → Mi → Fa → Sol → La. Hai nốt đầu ở dây dày, ba nốt sau nhích lên dây cạnh — tai chỉ nghe <b>một vùng đi lên</b>.</p>"},{"id":"v3","order":3,"logic":"LAM","type":"note_practice","title":"Đánh theo cả vùng","interactive":{"notes":[{"label":"Rê","freq":146.83,"string":4,"fret":0,"staff":-1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2},{"label":"La","freq":220,"string":3,"fret":2,"staff":3}]}},{"id":"v4","order":4,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình chơi liền 5 nốt Rê → La, đi lên đều","Mình thấy đây là một vùng nốt, không phải dây rời rạc"]}},{"id":"v5","order":5,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Rất vững! Bạn có thêm một vùng nốt. Bài cuối: nối vùng này với vùng cao thành cả một quãng tám."}]'::jsonb)
ON CONFLICT (id) DO UPDATE SET lesson_id = EXCLUDED.lesson_id, title = EXCLUDED.title, status = EXCLUDED.status, reward_xp = EXCLUDED.reward_xp, slides = EXCLUDED.slides;

