INSERT INTO flows (id, lesson_id, title, status, reward_xp, slides)
VALUES ('f2720000-0000-4000-8000-000000000004', 'a2720000-0000-4000-8000-000000000004', 'Bài 4: Cả vùng — Rê lên Rê (một quãng tám)', 'published', 10, '[{"id":"o1","order":1,"logic":"DAN","type":"callout","title":"Nối hai vùng","interactive":{"variant":"teacher"},"content":"Giờ nối <b>vùng thấp</b> và <b>vùng cao</b> thành một mạch dài: <b>Rê → Mi → Fa → Sol → La → Si → Đô → Rê</b> — trọn <b>một quãng tám</b>, qua 3 dây."},{"id":"o2","order":2,"logic":"NGHI","type":"text","title":"Đọc trôi qua 3 dây","content":"<p style=\"font-size:16px;line-height:1.7;margin:0;color:#3A352F\">Câu này đi từ <b>Rê thấp</b> (đáy khuông) lên tới <b>Rê cao</b> (giữa khuông) — chuyển mượt qua 3 dây. Đọc trôi cả câu = năng lực thật của tỉa nốt.</p>"},{"id":"o3","order":3,"logic":"LAM","type":"note_practice","title":"Đánh theo: cả quãng tám","interactive":{"notes":[{"label":"Rê","freq":146.83,"string":4,"fret":0,"staff":-1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2},{"label":"La","freq":220,"string":3,"fret":2,"staff":3},{"label":"Si","freq":246.94,"string":2,"fret":0,"staff":4},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6}]}},{"id":"o4","order":4,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình chơi liền Rê → Rê, chuyển dây mượt","Mình nghe ra giai điệu đi lên trọn một quãng tám"]}},{"id":"o5","order":5,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Xuất sắc! Bạn đã đọc và chơi trọn một quãng tám ở thế tay 1 — nền của mọi bài tỉa nốt về sau."}]'::jsonb)
