INSERT INTO flows (id, lesson_id, title, status, reward_xp, slides)
VALUES ('f2730000-0000-4000-8000-000000000002', 'a2730000-0000-4000-8000-000000000002', 'Bài 1: Happy Birthday', 'published', 15, '[{"id":"h1","order":1,"logic":"DAN","type":"callout","title":"Chơi Happy Birthday","interactive":{"variant":"teacher"},"content":"Bài đầu tiên: <b>Happy Birthday</b> — khúc chúc mừng sinh nhật ai cũng biết! Nó dùng đúng các nốt bạn đã học, trải trên <b>cả 3 dây</b>."},{"id":"h2","order":2,"logic":"NGHI","type":"text","title":"Đi qua 3 dây","content":"<p style=\"font-size:16px;line-height:1.7;margin:0;color:#3A352F\">Bài này đi từ vùng thấp (<b>Sol – La</b> dây 3) qua <b>Si – Đô – Rê</b> (dây 2) lên tới <b>Mi – Fa – Sol</b> (dây 1). Có chỗ nhảy xa (đoạn \"birthday dear...\") — cứ <b>chậm rãi</b>. Bấm <b>Nghe mẫu</b> để nghe đúng giai điệu trước.</p>"},{"id":"h3","order":3,"logic":"LAM","type":"note_practice","title":"Đánh theo: Happy Birthday","interactive":{"notes":[{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":0.75},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":0.25},{"label":"La","freq":220,"string":3,"fret":2,"staff":3,"dur":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"Si","freq":246.94,"string":2,"fret":0,"staff":4,"dur":2},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":0.75},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":0.25},{"label":"La","freq":220,"string":3,"fret":2,"staff":3,"dur":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":2},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":0.75},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":0.25},{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"Si","freq":246.94,"string":2,"fret":0,"staff":4,"dur":1},{"label":"La","freq":220,"string":3,"fret":2,"staff":3,"dur":1},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8,"dur":0.75},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8,"dur":0.25},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":2}]}},{"id":"h4","order":4,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình chơi hết được giai điệu, đúng các nốt","Mình nhận ra đúng bài Happy Birthday","Mình chuyển được qua cả 3 dây"]}},{"id":"h5","order":5,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Tuyệt vời! Bạn vừa chơi trọn một bài hát <b>qua cả 3 dây</b> — áp dụng mọi nốt đã học. Bài sau: một giai điệu quen khác — Ode to Joy."}]'::jsonb)
